# @cctt_verify {"v":2,"sym":"sympy.simplify.tests.test_fu.test_TR3","kind":"function","src_hash":"bd29fc496bd56eaf","in":{"base":"Any"},"out":{"base":"Any","pred":"TR3(cos(y - x * (y - x))) == cos(x * (x - y) + y) and cos(pi / 2 + x) == -sin(x) and cos(30 * pi / 2 + x) == -cos(x) and eq.has(9 * pi) and TR3(eq) == sin(pi / 11) and verify_numerically(i, j) and i.func != j.func"},"spec":{"lhs":"test_TR3()","rhs":"test_TR3 produces the expected output","over":{"base":"Any"},"name":"test_TR3_correct"},"guarantee":"test_TR3 produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.simplify.tests.test_fu.test_TR3_correct","statement":"Path(test_TR3(x), test_TR3 produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"ea34e1c791145ad2"}
def test_TR3():
    assert TR3(cos(y - x*(y - x))) == cos(x*(x - y) + y)
    assert cos(pi/2 + x) == -sin(x)
    assert cos(30*pi/2 + x) == -cos(x)

    for f in (cos, sin, tan, cot, csc, sec):
        i = f(pi*Rational(3, 7))
        j = TR3(i)
        assert verify_numerically(i, j) and i.func != j.func

    with evaluate(False):
        eq = cos(9*pi/22)
    assert eq.has(9*pi) and TR3(eq) == sin(pi/11)


