# @cctt_verify {"v":2,"sym":"sympy.simplify.tests.test_fu.test_TR12i","kind":"function","src_hash":"302295577aa34cc9","in":{"base":"Any"},"out":{"base":"Any","pred":"TR12i((ta + tb) / (-ta * tb + 1)) == tan(a + b) and TR12i((ta + tb) / (ta * tb - 1)) == -tan(a + b) and TR12i((-ta - tb) / (ta * tb - 1)) == tan(a + b) and TR12i(eq.expand()) == -3 * tan(a + b) * tan(a + c) / (tan(a) + tan(b) - 1) / 2 and TR12i(tan(x) / sin(x)) == tan(x) / sin(x) and TR12i(eq) == eq and TR12i(eq) == eq and TR12i(eq) == eq and TR12i(eq) == -(a + 1) ** 2 * tan(a + b)"},"spec":{"lhs":"test_TR12i()","rhs":"test_TR12i produces the expected output","over":{"base":"Any"},"name":"test_TR12i_correct"},"guarantee":"test_TR12i produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.simplify.tests.test_fu.test_TR12i_correct","statement":"Path(test_TR12i(x), test_TR12i produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"4d71b1d37f9e90d9"}
def test_TR12i():
    ta, tb, tc = [tan(i) for i in (a, b, c)]
    assert TR12i((ta + tb)/(-ta*tb + 1)) == tan(a + b)
    assert TR12i((ta + tb)/(ta*tb - 1)) == -tan(a + b)
    assert TR12i((-ta - tb)/(ta*tb - 1)) == tan(a + b)
    eq = (ta + tb)/(-ta*tb + 1)**2*(-3*ta - 3*tc)/(2*(ta*tc - 1))
    assert TR12i(eq.expand()) == \
        -3*tan(a + b)*tan(a + c)/(tan(a) + tan(b) - 1)/2
    assert TR12i(tan(x)/sin(x)) == tan(x)/sin(x)
    eq = (ta + cos(2))/(-ta*tb + 1)
    assert TR12i(eq) == eq
    eq = (ta + tb + 2)**2/(-ta*tb + 1)
    assert TR12i(eq) == eq
    eq = ta/(-ta*tb + 1)
    assert TR12i(eq) == eq
    eq = (((ta + tb)*(a + 1)).expand())**2/(ta*tb - 1)
    assert TR12i(eq) == -(a + 1)**2*tan(a + b)


