# @cctt_verify {"v":2,"sym":"sympy.simplify.tests.test_fu.test_TR14","kind":"function","src_hash":"26d66035beded3de","in":{"base":"Any"},"out":{"base":"Any","pred":"TR14(eq) == ans and TR14(1 / eq) == 1 / ans and TR14((cos(x) - 1) ** 2 * (cos(x) + 1) ** 2) == ans ** 2 and TR14((cos(x) - 1) ** 2 * (cos(x) + 1) ** 3) == ans ** 2 * (cos(x) + 1) and TR14((cos(x) - 1) ** 3 * (cos(x) + 1) ** 2) == ans ** 2 * (cos(x) - 1) and TR14(eq) == eq and TR14(eq) == eq and TR14(eq) == eq and TR14((cos(x) - 1) ** i * (cos(x) + 1) ** i) == ans ** i and TR14((sin(x) - 1) ** i * (sin(x) + 1) ** i) == (-cos(x) ** 2) ** i and TR14(eq) in [(cos(x) - 1) * ans ** i, eq] and TR14((sin(x) - 1) * (sin(x) + 1)) == -cos(x) ** 2 and TR14(p1 * p2 * p3 * (x - 1)) == -18 * ((x - 1) * sin(x) ** 2 * sin(y) ** 4)"},"spec":{"lhs":"test_TR14()","rhs":"test_TR14 produces the expected output","over":{"base":"Any"},"name":"test_TR14_correct"},"guarantee":"test_TR14 produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.simplify.tests.test_fu.test_TR14_correct","statement":"Path(test_TR14(x), test_TR14 produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"c7776673008b6b20"}
def test_TR14():
    eq = (cos(x) - 1)*(cos(x) + 1)
    ans = -sin(x)**2
    assert TR14(eq) == ans
    assert TR14(1/eq) == 1/ans
    assert TR14((cos(x) - 1)**2*(cos(x) + 1)**2) == ans**2
    assert TR14((cos(x) - 1)**2*(cos(x) + 1)**3) == ans**2*(cos(x) + 1)
    assert TR14((cos(x) - 1)**3*(cos(x) + 1)**2) == ans**2*(cos(x) - 1)
    eq = (cos(x) - 1)**y*(cos(x) + 1)**y
    assert TR14(eq) == eq
    eq = (cos(x) - 2)**y*(cos(x) + 1)
    assert TR14(eq) == eq
    eq = (tan(x) - 2)**2*(cos(x) + 1)
    assert TR14(eq) == eq
    i = symbols('i', integer=True)
    assert TR14((cos(x) - 1)**i*(cos(x) + 1)**i) == ans**i
    assert TR14((sin(x) - 1)**i*(sin(x) + 1)**i) == (-cos(x)**2)**i
    # could use extraction in this case
    eq = (cos(x) - 1)**(i + 1)*(cos(x) + 1)**i
    assert TR14(eq) in [(cos(x) - 1)*ans**i, eq]

    assert TR14((sin(x) - 1)*(sin(x) + 1)) == -cos(x)**2
    p1 = (cos(x) + 1)*(cos(x) - 1)
    p2 = (cos(y) - 1)*2*(cos(y) + 1)
    p3 = (3*(cos(y) - 1))*(3*(cos(y) + 1))
    assert TR14(p1*p2*p3*(x - 1)) == -18*((x - 1)*sin(x)**2*sin(y)**4)


